import{c as s,Q as a,j as r,m as o}from"./chunks/framework.DVkeSyfh.js";const h=JSON.parse('{"title":"CLASS tab and promoted classifiers","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/class-tab.md","filePath":"user-guide/class-tab.md","lastUpdated":null}'),i={name:"user-guide/class-tab.md"};function t(l,e,c,n,d,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="class-tab-and-promoted-classifiers" tabindex="-1">CLASS tab and promoted classifiers <a class="header-anchor" href="#class-tab-and-promoted-classifiers" aria-label="Permalink to &quot;CLASS tab and promoted classifiers&quot;">​</a></h1><p>Audience: Rhythm Lab users<br> Goal: use promoted classifier scores in the main UI<br> Type: how-to</p><p>The <code>CLASS</code> tab discovers promoted local classifier profiles from <code>models/classifiers/*/model.json</code>. A promoted classifier writes scores into the project database, then those scores become filters or modifiers in UI workflows.</p><h2 id="what-the-score-means" tabindex="-1">What the score means <a class="header-anchor" href="#what-the-score-means" aria-label="Permalink to &quot;What the score means&quot;">​</a></h2><p>For binary classifier profiles, the user-facing score is the promoted model&#39;s positive-label probability stored in <code>track_classifier_scores.score</code>.</p><p>Missing scores are neutral in SET. They do not count as a negative judgment.</p><h2 id="score-a-promoted-classifier" tabindex="-1">Score a promoted classifier <a class="header-anchor" href="#score-a-promoted-classifier" aria-label="Permalink to &quot;Score a promoted classifier&quot;">​</a></h2><p>Use the classifier scoring control for one promoted profile. The app should score only missing rows for that classifier key unless you intentionally reset that classifier&#39;s rows.</p><p>After retraining and promoting a new model for the same key, reset only that classifier&#39;s stored scores and rescore it.</p><h2 id="keep-scopes-separate" tabindex="-1">Keep scopes separate <a class="header-anchor" href="#keep-scopes-separate" aria-label="Permalink to &quot;Keep scopes separate&quot;">​</a></h2><p>Classifier scoring:</p><ul><li>reads existing SONARA, MERT, and MAEST-derived inputs;</li><li>writes only SQLite <code>track_classifier_scores</code>;</li><li>does not decode audio for normal scoring;</li><li>does not clear scores for unrelated classifier keys.</li></ul><p>Use <a href="./../workflows/train-personal-classifier.html">Train a personal classifier</a> for the labeling/training/promotion workflow.</p>',13)])])}const m=s(i,[["render",t]]);export{h as __pageData,m as default};
